const fmt=t=>new Date(t).toLocaleString('sv',{timeZone:'Asia/Riyadh'}).split(' ')[0];
const today=fmt(Date.now());
const due=fmt(Date.now()+7*86400000);
const monthLabel=new Date().toLocaleString('en',{timeZone:'Asia/Riyadh',month:'long',year:'numeric'});
const tabName='Creatives-'+today.slice(0,7);
const classify=r=>{if(r.qual_ratio>0.50&&r.cpl<=25)return'Winner';if(r.qual_ratio>0.50)return'Optimise';return'Underperformer';};
const rows=$input.all().map(i=>{const d=i.json;return[d.channel||'',d.ad_name||'',d.ad_id||'',d.clicks||0,d.ctr||0,d.leads||0,d.qualified_leads||0,d.qual_ratio||0,d.cpl||0,d.spend||0,classify(d)];});
const headers=['channel','ad_name','ad_id','clicks','ctr','leads','qualified_leads','qual_ratio','cpl','spend','status'];
const sheetLink='https://docs.google.com/spreadsheets/d/120o-BXLdpvT5phvTY2ePiYcKiyQi5kcXedLuq_cDtVg';
const winners=rows.filter(r=>r[10]==='Winner').map(r=>r[0]+': '+r[1]+' — '+(r[7]*100).toFixed(0)+'% qual, $'+r[8]+' CPL').join('\n')||'None';
const under=rows.filter(r=>r[10]==='Underperformer'&&(r[7]===0||r[8]>50)).map(r=>r[0]+': '+r[1]+' ($'+r[8]+' CPL, '+(r[7]*100).toFixed(0)+'% qual)').join('\n')||'None';
const notes='WINNING CREATIVES — '+monthLabel+'\nSheet: '+sheetLink+'\n\nTOP WINNERS:\n'+winners+'\n\nUNDERPERFORMERS:\n'+under+'\n\n---\nCreated: '+today+' | Due: '+due+' | Priority: Medium | Type: Recommendation | Channel: all | Asset level: ad | Action: optimize → [Creative Strategist]';
return [{json:{rows,headers,tabName,sheetLink,today,due,monthLabel,notes}}];

const fmt=t=>new Date(t).toLocaleString('sv',{timeZone:'Asia/Riyadh'}).split(' ')[0];
const today=fmt(Date.now());
const due=fmt(Date.now()+7*86400000);
const all=$input.all();
if(!all.length||!all[0].json.destination_url){return [{json:{skip:true,notes:'Monthly LP brief skipped — no SQLs last month.

---
Created: '+today}}];}
const d=all[0].json;
const ym=today.slice(0,7);
const channel=d.sample_campaign?.split('_')[0]||'All';
const notes='[DRAFT] LP DUPLICATE BRIEF — '+ym+' Winner: '+d.destination_url+'

WINNING LP: '+d.destination_url+' | SQLs: '+d.sqls+' | Leads: '+d.leads+' | CVR: '+d.cvr_pct+'% | CPQL: $'+d.cpql_usd+'

HYPOTHESIS: A duplicate of '+d.destination_url+' with refreshed hero + CTA will match or beat $'+d.cpql_usd+' CPQL within 14 days.

WHY DUPLICATE: LP already converts — preserve structure, refresh creative only. Same form, same ZATCA badge above fold.

VARIANT CHANGES: hero image | H1 alternative | CTA text only. No structural changes.

SUCCESS CRITERION: CPQL ≤ $'+d.cpql_usd+' after 14 days. Min 50 leads per variant.

ZATCA BADGE: above fold, non-negotiable. UI/UX to confirm desktop + mobile (375px).

---
Created: '+today+' | Due: '+due+' | Priority: Normal | Type: LP Duplicate | Channel: '+channel+' | Asset level: LP';
return [{json:{skip:false,title:'[DRAFT] LP Duplicate Brief — '+ym+' Winner: '+d.destination_url,notes,due}}];

// Build prompt for performance-lead — takes growth-analyst output as context
const resp = $input.first().json;
const block = (resp.content || []).find(b => b.type === 'tool_use');
const analysis = block?.input || {};

const systemPrompt = 'You are the Performance Lead at Qoyod. Review the Growth Analyst weekly report and add strategic context. ' +
  'Validate findings, escalate CPQL regressions (>$160 = pause; $130-160 = warning), identify cross-channel patterns, ' +
  'add a 1-paragraph executive summary, and confirm or override analyst actions with reasoning. ' +
  'CPQL zones: scale <$85 | acceptable $85-$130 | warning $130-$160 | pause >$160. ' +
  'Min 14-day window for pause/scale. Spend in USD.';

const digest = analysis.digest || JSON.stringify(analysis).slice(0, 3000);

const tools = [{
  name: 'weekly_digest',
  description: 'Weekly digest — performance-lead final review',
  input_schema: {
    type: 'object',
    required: ['digest', 'actions'],
    properties: {
      digest: {type: 'string'},
      actions: {type: 'array', items: {type: 'object', required: ['title','description','priority'],
        properties: {title:{type:'string'}, description:{type:'string'}, priority:{type:'string',enum:['high','medium','low']}, channel:{type:'string'}}}}
    }
  }
}];

return [{json: {
  system: systemPrompt,
  messages: [{role: 'user', content: 'Growth Analyst report:\n\n' + digest + '\n\nProvide your strategic review.'}],
  tools,
  tool_choice: {type: 'required'}
}}];

// Build prompt for creative-strategist — analyzes formatted creative report data
const rows = $input.all().map(i => i.json);

const systemPrompt = 'You are the Creative Strategist at Qoyod. Analyze this month creative performance data. ' +
  'Identify top-performing creatives (qual_ratio > 0.50 AND CPL <= $25), underperformers, and optimization opportunities. ' +
  'Classify each creative: Winner = qual_ratio>0.50 AND CPL<=$25 | Optimise = qual_ratio>0.50 AND CPL>$25 | Underperformer = qual_ratio<=0.50. ' +
  'Provide actionable creative briefs for next month (new angle for winners, revision notes for optimise, kill for underperformers). ' +
  'Respond using the creative_report tool.';

const creativeData = rows.map(r => 
  (r.creative_name || r.ad_name || 'unknown') + ': CPL=$' + (r.cpl || 0).toFixed(2) + 
  ', qual_ratio=' + (r.qual_ratio || 0).toFixed(2) + 
  ', leads=' + (r.leads_total || 0) + ', sqls=' + (r.leads_qualified || 0)
).join('\n');

const tools = [{
  name: 'creative_report',
  description: 'Creative strategist monthly report',
  input_schema: {
    type: 'object', required: ['summary', 'creatives'],
    properties: {
      summary: {type: 'string', description: 'Executive summary of creative performance'},
      creatives: {type: 'array', items: {type: 'object', required: ['name','classification','recommendation'],
        properties: {name:{type:'string'}, classification:{type:'string',enum:['winner','optimise','underperformer']}, 
          cpl:{type:'number'}, qual_ratio:{type:'number'}, recommendation:{type:'string'}}}}
    }
  }
}];

return [{json: {
  system: systemPrompt,
  messages: [{role: 'user', content: 'Creative performance this month:\n\n' + creativeData}],
  tools,
  tool_choice: {type: 'required'},
  original_rows: rows
}}];

